def bubble_sort(arr):
    n=len(arr)
    for i in range(n):
        for j in range(n-i-1):
            if arr[j]>arr[j+1]: arr[j],arr[j+1]=arr[j+1],arr[j]
    return arr

def linear_search(arr,x):
    for i,v in enumerate(arr):
        if v==x: return i
    return -1

